import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Agent Operating Model","description":"","frontmatter":{},"headers":[],"relativePath":"development/agent-model.md","filePath":"development/agent-model.md","lastUpdated":1775719799000}'),d={name:"development/agent-model.md"};function n(c,t,s,i,l,p){return a(),o("div",null,[...t[0]||(t[0]=[r(`<h1 id="agent-operating-model" tabindex="-1">Agent Operating Model <a class="header-anchor" href="#agent-operating-model" aria-label="Permalink to &quot;Agent Operating Model&quot;">​</a></h1><p><strong>Last updated:</strong> 2026-03-22 <strong>Canonical agent guide:</strong> <a href="https://github.com/rustchatio/rustchat/blob/main/AGENTS.md" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a> (root) — read that first for full workflow details</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This document describes the LLM agent operating model for rustchat: which agents are authorized, what skills they use, and what scope boundaries apply. It structures the information per the LLM Development Operating Model v2.0.</p><p>The machine-readable contracts live in <code>.governance/agent-contracts.yml</code>. This doc is the human-readable summary.</p><hr><h2 id="_1-agent-roles" tabindex="-1">1. Agent Roles <a class="header-anchor" href="#_1-agent-roles" aria-label="Permalink to &quot;1. Agent Roles&quot;">​</a></h2><p>Three agents are defined for rustchat:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Mode</th><th>Role</th></tr></thead><tbody><tr><td><code>backend-agent</code></td><td>bounded-write</td><td>Implements backend features and fixes</td></tr><tr><td><code>frontend-agent</code></td><td>bounded-write</td><td>Implements frontend features and fixes</td></tr><tr><td><code>compat-agent</code></td><td>read-only</td><td>Performs Mattermost compatibility analysis, produces design artifacts</td></tr></tbody></table><h3 id="backend-agent" tabindex="-1">backend-agent <a class="header-anchor" href="#backend-agent" aria-label="Permalink to &quot;backend-agent&quot;">​</a></h3><p><strong>Allowed paths:</strong> <code>backend/src/**</code>, <code>backend/tests/**</code>, <code>backend/migrations/**</code>, <code>push-proxy/**</code></p><p><strong>Prohibited without explicit approval:</strong></p><ul><li><code>backend/src/auth/**</code> — requires explicit human approval</li><li><code>backend/src/api/v4/**</code> — requires compat-reviewer co-approval (<code>@zoorpha</code>)</li><li><code>backend/src/mattermost_compat/**</code> — requires compat-reviewer co-approval</li><li><code>backend/src/a2a/**</code> — requires senior review</li><li><code>.governance/**</code>, <code>frontend/**</code> — always prohibited</li></ul><p><strong>Limits:</strong> ≤10 files, ≤300 lines per PR. Tests required. Human review required.</p><p><strong>ADR required for:</strong> auth changes, permission changes, API contract changes.</p><h3 id="frontend-agent" tabindex="-1">frontend-agent <a class="header-anchor" href="#frontend-agent" aria-label="Permalink to &quot;frontend-agent&quot;">​</a></h3><p><strong>Allowed paths:</strong> <code>frontend/src/**</code>, <code>frontend/e2e/**</code></p><p><strong>Prohibited:</strong> <code>backend/**</code>, <code>.governance/**</code></p><p><strong>Limits:</strong> ≤10 files, ≤300 lines per PR. Human review required. <strong>Tests:</strong> Not required (explicitly set to <code>false</code> in contract).</p><h3 id="compat-agent" tabindex="-1">compat-agent <a class="header-anchor" href="#compat-agent" aria-label="Permalink to &quot;compat-agent&quot;">​</a></h3><p><strong>Mode:</strong> Read-only — cannot write production code, cannot approve PRs.</p><p><strong>Can read:</strong> <code>backend/compat/**</code>, <code>backend/src/api/v4/**</code>, <code>backend/src/mattermost_compat/**</code>, <code>tools/mm-compat/**</code></p><p><strong>Can write (analysis output only):</strong> <code>previous-analyses/**</code>, <code>docs/superpowers/specs/**</code>, <code>docs/superpowers/plans/**</code><strong>Prohibited:</strong> <code>.governance/**</code> — always prohibited.</p><p><strong>Applicable skills:</strong> <code>mattermost-api-parity</code>, <code>mm-endpoint-contract-parity</code>, <code>mm-websocket-calls-parity</code>, <code>mm-mobile-journey-parity</code></p><hr><h2 id="_2-skills-system" tabindex="-1">2. Skills System <a class="header-anchor" href="#_2-skills-system" aria-label="Permalink to &quot;2. Skills System&quot;">​</a></h2><p>7 capability skills are defined in <code>.agents/skills/</code>:</p><table tabindex="0"><thead><tr><th>Skill</th><th>Domain</th></tr></thead><tbody><tr><td><code>mattermost-api-parity</code></td><td>Compat: Mattermost HTTP API analysis</td></tr><tr><td><code>mm-endpoint-contract-parity</code></td><td>Compat: endpoint contract comparison</td></tr><tr><td><code>mm-websocket-calls-parity</code></td><td>Compat: WebSocket event contract analysis</td></tr><tr><td><code>mm-mobile-journey-parity</code></td><td>Compat: mobile user journey coverage</td></tr><tr><td><code>production-readiness-gate</code></td><td>Quality: pre-release checklist</td></tr><tr><td><code>user-validation</code></td><td>Quality: user-facing behavior verification</td></tr><tr><td><code>ai-summarization-rag</code></td><td>Feature: AI summarization / RAG pipeline</td></tr></tbody></table><p><strong>Relationship to agent contracts:</strong> Skills define <em>how</em> (capability, method, output format). Contracts define <em>where</em> (allowed paths, scope boundaries). A skill tells the agent what to do; the contract tells it where it is allowed to do it.</p><p>For compat-agent: only the 4 compat skills apply. For backend-agent and frontend-agent: any non-compat skill.</p><hr><h2 id="_3-workflow" tabindex="-1">3. Workflow <a class="header-anchor" href="#_3-workflow" aria-label="Permalink to &quot;3. Workflow&quot;">​</a></h2><p>All agent work follows the <strong>plan-first</strong> workflow:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Brainstorm → spec (docs/superpowers/specs/YYYY-MM-DD-&lt;topic&gt;-design.md)</span></span>
<span class="line"><span>2. Write plan (docs/superpowers/plans/YYYY-MM-DD-&lt;topic&gt;.md)</span></span>
<span class="line"><span>3. Execute plan task-by-task (subagent-driven-development or executing-plans)</span></span>
<span class="line"><span>4. Two-stage review per task: spec compliance → code quality</span></span>
<span class="line"><span>5. finishing-a-development-branch</span></span></code></pre></div><p>No ad-hoc changes to protected paths. No implementation without a prior spec.</p><hr><h2 id="_4-compatibility-first-rule" tabindex="-1">4. Compatibility-First Rule <a class="header-anchor" href="#_4-compatibility-first-rule" aria-label="Permalink to &quot;4. Compatibility-First Rule&quot;">​</a></h2><p>Any change to the Mattermost compatibility surface (<code>backend/src/api/v4/**</code>, <code>backend/src/mattermost_compat/**</code>, <code>backend/compat/**</code>) requires:</p><ol><li>Compat reviewer co-approval (<code>@zoorpha</code> per <code>CODEOWNERS</code>)</li><li>Risk tier elevated (automatic per <code>protected-paths.yml</code>)</li><li>Compat contract tests pass</li></ol><p>When in doubt whether a change touches the compat surface, treat it as if it does.</p><hr><h2 id="_5-boundaries-summary" tabindex="-1">5. Boundaries Summary <a class="header-anchor" href="#_5-boundaries-summary" aria-label="Permalink to &quot;5. Boundaries Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Area</th><th>backend-agent</th><th>frontend-agent</th><th>compat-agent</th></tr></thead><tbody><tr><td><code>backend/src/</code> (non-protected)</td><td>✅ write</td><td>❌</td><td>✅ read</td></tr><tr><td><code>backend/src/api/v4/</code></td><td>⚠️ co-approval</td><td>❌</td><td>✅ read</td></tr><tr><td><code>backend/src/auth/</code></td><td>⚠️ explicit approval</td><td>❌</td><td>❌</td></tr><tr><td><code>backend/src/mattermost_compat/</code></td><td>⚠️ co-approval</td><td>❌</td><td>✅ read</td></tr><tr><td><code>backend/src/a2a/</code></td><td>⚠️ senior review</td><td>❌</td><td>❌</td></tr><tr><td><code>backend/migrations/</code></td><td>✅ write</td><td>❌</td><td>❌</td></tr><tr><td><code>backend/tests/</code></td><td>✅ write</td><td>❌</td><td>❌</td></tr><tr><td><code>backend/compat/</code></td><td>❌</td><td>❌</td><td>✅ read</td></tr><tr><td><code>frontend/src/</code></td><td>❌</td><td>✅ write</td><td>❌</td></tr><tr><td><code>frontend/e2e/</code></td><td>❌</td><td>✅ write</td><td>❌</td></tr><tr><td><code>.governance/</code></td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td><code>docs/superpowers/specs/</code></td><td>❌</td><td>❌</td><td>✅ write</td></tr><tr><td><code>docs/superpowers/plans/</code></td><td>❌</td><td>❌</td><td>✅ write</td></tr></tbody></table><hr><h2 id="_6-cross-references" tabindex="-1">6. Cross-References <a class="header-anchor" href="#_6-cross-references" aria-label="Permalink to &quot;6. Cross-References&quot;">​</a></h2><ul><li>Full agent workflow guide: <a href="https://github.com/rustchatio/rustchat/blob/main/AGENTS.md" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></li><li>Machine-readable contracts: <a href="https://github.com/rustchatio/rustchat/blob/main/.governance/agent-contracts.yml" target="_blank" rel="noreferrer"><code>.governance/agent-contracts.yml</code></a></li><li>Risk tier definitions: <a href="https://github.com/rustchatio/rustchat/blob/main/.governance/risk-tiers.yml" target="_blank" rel="noreferrer"><code>.governance/risk-tiers.yml</code></a></li><li>Protected paths: <a href="https://github.com/rustchatio/rustchat/blob/main/.governance/protected-paths.yml" target="_blank" rel="noreferrer"><code>.governance/protected-paths.yml</code></a></li><li>Code ownership: <a href="https://github.com/rustchatio/rustchat/blob/main/.github/CODEOWNERS" target="_blank" rel="noreferrer"><code>.github/CODEOWNERS</code></a></li></ul>`,47)])])}const g=e(d,[["render",n]]);export{m as __pageData,g as default};
